const reports = $json.data || [];
if (reports.length === 0) return [];
return reports.map(r => ({ json: r }));

const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
const priorityEmoji = { URGENT: "🔴", HIGH: "🟠", MEDIUM: "🔵", LOW: "⚪" };
const projectTypeLabel = { TASK: "Task", BUG: "Bug", FEATURE: "Feature", STORY: "Story", EPIC: "Epic" };

const fmtDate = (dateStr) => {
  if (!dateStr) return "—";
  const vn = new Date(new Date(dateStr).getTime() + 7 * 60 * 60 * 1000);
  return `${MONTHS[vn.getUTCMonth()]} ${vn.getUTCDate()} (${DAYS[vn.getUTCDay()]})`;
};

const fmtMoney = (amount) => {
  if (amount === null || amount === undefined) return "—";
  return `${new Intl.NumberFormat("vi-VN").format(Math.round(Math.abs(amount)))} ₫`;
};

const periodLabel = (s, e) => `${fmtDate(s)} → ${fmtDate(e)}`;
const hasSection = (sections, key) => !sections?.length || sections.includes(key);
const countDone = (items = []) => items.filter((item) => item.completed).length;

const pushSection = (parts, title, lines) => {
  if (!lines.length) return;
  if (parts.length) parts.push("");
  parts.push(title);
  parts.push(...lines);
};

const renderGoalProgress = (goal) => {
  const pct = goal.targetCount > 0 ? Math.round((goal.currentCount / goal.targetCount) * 100) : 0;
  const icon = goal.completed ? "✅" : pct >= 50 ? "🟡" : "⏳";
  return `• ${icon} ${goal.title}: ${goal.currentCount}/${goal.targetCount} ${goal.unit || "times"}${goal.targetCount > 0 ? ` (${pct}%)` : ""}`;
};

const renderWeeklySummary = (d) => {
  const sections = d.sections || [];
  const parts = [
    `📊 <b>Weekly Summary</b>`,
    `📅 ${periodLabel(d.period.start, d.period.end)}`,
  ];

  if (hasSection(sections, "GOALS")) {
    const goals = d.goals || [];
    const lines = goals.length
      ? goals.slice(0, 6).map(renderGoalProgress)
      : ["• No active goals"];
    pushSection(parts, `🎯 <b>Goals (${countDone(goals)}/${goals.length} completed)</b>`, lines);
  }

  if (hasSection(sections, "PROJECT")) {
    const done = d.project?.done || [];
    const inProgress = d.project?.inProgress || [];
    const lines = [];
    lines.push(`• Done: ${done.length}`);
    if (done.length) {
      done.slice(0, 5).forEach((item) => {
        const due = item.deadline ? ` – ${fmtDate(item.deadline)}` : "";
        lines.push(`  ◦ ${item.title}${due} <i>[${item.project}]</i>`);
      });
      if (done.length > 5) lines.push(`  ◦ … and ${done.length - 5} more`);
    }
    lines.push(`• In Progress: ${inProgress.length}`);
    if (inProgress.length) {
      inProgress.slice(0, 5).forEach((item) => {
        const due = item.deadline ? ` – due ${fmtDate(item.deadline)}` : "";
        lines.push(`  ◦ ${item.title}${due} <i>[${item.project}]</i>`);
      });
      if (inProgress.length > 5) lines.push(`  ◦ … and ${inProgress.length - 5} more`);
    }
    pushSection(parts, `🧩 <b>Project (${d.project?.total ?? done.length + inProgress.length})</b>`, lines);
  }

  if (hasSection(sections, "TASKS")) {
    const done = d.tasks?.done || [];
    const inProgress = d.tasks?.inProgress || [];
    const lines = [];
    lines.push(`• Done: ${done.length}`);
    if (done.length) {
      done.slice(0, 5).forEach((item) => {
        const due = item.dueDate ? ` – ${fmtDate(item.dueDate)}` : "";
        lines.push(`  ◦ ${item.title}${due}`);
      });
      if (done.length > 5) lines.push(`  ◦ … and ${done.length - 5} more`);
    }
    lines.push(`• In Progress: ${inProgress.length}`);
    if (inProgress.length) {
      inProgress.slice(0, 5).forEach((item) => {
        const due = item.dueDate ? ` – due ${fmtDate(item.dueDate)}` : "";
        lines.push(`  ◦ ${item.title}${due}`);
      });
      if (inProgress.length > 5) lines.push(`  ◦ … and ${inProgress.length - 5} more`);
    }
    pushSection(parts, `✅ <b>Tasks (${d.tasks?.total ?? done.length + inProgress.length})</b>`, lines);
  }

  if (hasSection(sections, "HOUSEWORK")) {
    const housework = d.housework || [];
    const lines = housework.length
      ? housework.slice(0, 5).map((item) => `• ${item.title}${item.completedDate ? ` – ${fmtDate(item.completedDate)}` : ""}`)
      : ["• No housework completed"];
    pushSection(parts, `🏠 <b>Housework (${housework.length})</b>`, lines);
  }

  if (hasSection(sections, "CALENDAR")) {
    const calendar = d.calendar || [];
    const lines = calendar.length
      ? calendar.slice(0, 5).map((item) => {
          const loc = item.location ? ` @ ${item.location}` : "";
          return `• ${item.title} – ${fmtDate(item.startDate)}${loc}`;
        })
      : ["• No calendar events"];
    pushSection(parts, `📅 <b>Calendar (${calendar.length})</b>`, lines);
  }

  if (hasSection(sections, "EXPENSES")) {
    const expenses = d.expenses || { totalPaid: 0, totalReceived: 0, net: 0 };
    const netSign = expenses.net >= 0 ? "+" : "-";
    const lines = [
      `• Paid: ${fmtMoney(expenses.totalPaid)}`,
      `• Received: ${fmtMoney(expenses.totalReceived)}`,
      `• Net: ${netSign}${fmtMoney(expenses.net)}`,
    ];
    pushSection(parts, `💰 <b>Expenses</b>`, lines);
  }

  if (hasSection(sections, "ASSETS")) {
    const assets = d.assets || [];
    const lines = assets.length
      ? assets.slice(0, 5).map((item) => {
          const desc = item.description ? ` – ${item.description}` : "";
          const cost = item.cost ? ` (${fmtMoney(item.cost)})` : "";
          return `• ${item.asset}: ${item.serviceType}${desc} – ${fmtDate(item.serviceDate)}${cost}`;
        })
      : ["• No asset maintenance records"];
    pushSection(parts, `🛠️ <b>Assets (${assets.length})</b>`, lines);
  }

  if (hasSection(sections, "LEARNING")) {
    const learning = d.learning || [];
    const lines = learning.length
      ? learning.slice(0, 5).map((item) => {
          const topic = item.topic ? ` <i>[${item.topic}]</i>` : "";
          const progress = typeof item.progress === "number" ? ` – ${item.progress}%` : "";
          return `• ${item.title}${topic} – ${item.status || "IN_PROGRESS"}${progress}`;
        })
      : ["• No learning updates"];
    pushSection(parts, `📘 <b>Learning (${learning.length})</b>`, lines);
  }

  if (hasSection(sections, "IDEAS")) {
    const ideas = d.ideas || [];
    const lines = ideas.length
      ? ideas.slice(0, 5).map((item) => {
          const category = item.category ? ` <i>[${item.category}]</i>` : "";
          return `• ${item.title}${category} – ${item.status || "OPEN"}`;
        })
      : ["• No idea updates"];
    pushSection(parts, `💡 <b>Ideas (${ideas.length})</b>`, lines);
  }

  return {
    text: parts.join("\n"),
    emailSubject: `📊 Weekly Summary – ${periodLabel(d.period.start, d.period.end)}`,
  };
};

const renderForwardTasks = (d) => {
  const sections = d.sections || [];
  const title =
    d.reportType === "TODAY_TASKS"
      ? "Today Tasks"
      : d.reportType === "TOMORROW_TASKS"
      ? "Tomorrow Tasks"
      : "Next Week Action Items";

  const parts = [
    `📋 <b>${title}</b>`,
    `📅 ${periodLabel(d.period.start, d.period.end)}`,
  ];

  if (hasSection(sections, "GOALS")) {
    const goals = d.goals || [];
    const lines = goals.length
      ? goals.map((goal) => {
          const pct = goal.targetCount > 0 ? Math.round((goal.currentCount / goal.targetCount) * 100) : 0;
          const icon = goal.completed ? "✅" : pct >= 50 ? "🟡" : "⏳";
          const due = goal.dueDate ? ` – ${fmtDate(goal.dueDate)}` : "";
          return `• ${icon} ${goal.title}: ${goal.currentCount}/${goal.targetCount} ${goal.unit || "times"}${due}`;
        })
      : ["• No goals"];
    pushSection(parts, `🎯 <b>Goals (${goals.length})</b>`, lines);
  }

  if (hasSection(sections, "PROJECT")) {
    const project = d.project || [];
    const lines = project.length
      ? project.map((item) => {
          const emoji = priorityEmoji[item.priority] || "🔵";
          const due = item.deadline ? fmtDate(item.deadline) : "No deadline";
          const type = item.type ? `${projectTypeLabel[item.type] || item.type} • ` : "";
          return `• ${emoji} ${item.title} – ${type}${due} <i>[${item.project}]</i>`;
        })
      : ["• No project items"];
    pushSection(parts, `🧩 <b>Project (${project.length})</b>`, lines);
  }

  if (hasSection(sections, "TASKS")) {
    const tasks = d.tasks || [];
    const lines = tasks.length
      ? tasks.map((item) => {
          const emoji = priorityEmoji[item.priority] || "🔵";
          return `• ${emoji} ${item.title} – ${fmtDate(item.dueDate)}`;
        })
      : ["• No tasks"];
    pushSection(parts, `✅ <b>Tasks (${tasks.length})</b>`, lines);
  }

  if (hasSection(sections, "HOUSEWORK")) {
    const housework = d.housework || [];
    const lines = housework.length
      ? housework.map((item) => `• ${item.title} – ${fmtDate(item.dueDate)}`)
      : ["• No housework due"];
    pushSection(parts, `🏠 <b>Housework (${housework.length})</b>`, lines);
  }

  if (hasSection(sections, "CALENDAR")) {
    const calendar = d.calendar || [];
    const lines = calendar.length
      ? calendar.map((item) => {
          const loc = item.location ? ` @ ${item.location}` : "";
          return `• ${item.title} – ${fmtDate(item.startDate)}${loc}`;
        })
      : ["• No calendar events"];
    pushSection(parts, `📅 <b>Calendar (${calendar.length})</b>`, lines);
  }

  return {
    text: parts.join("\n"),
    emailSubject: `📋 ${title} – ${periodLabel(d.period.start, d.period.end)}`,
  };
};

const results = [];

for (const item of $input.all()) {
  const d = item.json.data;
  const user = d.user;
  let rendered = {
    text: `📋 <b>${d.reportType || "Report"}</b>\nNo formatter configured.`,
    emailSubject: `Report for ${user.name}`,
  };

  if (d.reportType === "WEEKLY_SUMMARY" || d.reportType === "SUMMARY") {
    rendered = renderWeeklySummary(d);
  } else if (
    d.reportType === "NEXT_WEEK_TASKS" ||
    d.reportType === "TODAY_TASKS" ||
    d.reportType === "TOMORROW_TASKS"
  ) {
    rendered = renderForwardTasks(d);
  }

  const emailHtml = rendered.text
    .replace(/\n/g, "<br>")
    .replace(/<b>(.*?)<\/b>/g, "<strong>$1</strong>")
    .replace(/<i>(.*?)<\/i>/g, "<em>$1</em>");

  results.push({
    json: {
      telegramText: rendered.text,
      emailSubject: rendered.emailSubject,
      emailHtml,
      telegramChatId: user.telegramChatId,
      notificationEmail: user.notificationEmail || user.email,
      notificationChannel: user.notificationChannel,
      userName: user.name,
    },
  });
}

return results;
